    def readStr(self):
        return input().rstrip('\n')


    def solve(self, board, n):
        result = [[0 for _ in range(n)] for _ in range(n)]
        queens = set()

        def placeQueens(row):
            if row == n:
                return True

            for col in range(n):
                if (row - 1, col) in queens or (row, col) in queens or (col - 1, row) in queens or (col, row) in queens:
                    continue

                queens.add((row, col))

                if placeQueens(row + 1):
                    return True

                queens.remove((row, col))

            return False

        if not placeQueens(0):
            return []

        for i in range(n):
            for j in range(n):
                if (i, j) in queens:
                    result[i][j] = 1

        return result

    def main(self):
